// Consolida los resultados de todas las fuentes en una sola estructura.
// Cada fuente puede haber fallado (onError: continue), por eso todo va con try/catch.
const fechas = $('Preparar Fechas').first().json;
const get = (name) => { try { return $(name).all().map(i => i.json || {}); } catch (e) { return []; } };
const trunc = (s, n = 350) => (s || '').toString().replace(/\s+/g, ' ').trim().slice(0, n);
const limpiar = arr => arr.filter(x => x.titulo || x.cargo).filter(x => x.link);

// --- SerpAPI: noticias (news_results) ---
const serpNews = (name) => get(name).flatMap(j => j.news_results || []).map(r => ({
  titulo: r.title, link: r.link,
  fuente: (r.source && r.source.name) || r.source || 'Google News',
  fecha: r.date || '', resumen: trunc(r.snippet), via: 'SerpAPI'
}));

// --- SerpAPI: resultados orgánicos (LinkedIn indexado) ---
const serpOrganic = (name) => get(name).flatMap(j => j.organic_results || []).map(r => ({
  titulo: r.title, link: r.link, fuente: 'LinkedIn (vía Google)',
  fecha: r.date || '', resumen: trunc(r.snippet), via: 'SerpAPI'
}));

// --- SerpAPI: Google Jobs ---
const serpJobs = get('SerpAPI Google Jobs').flatMap(j => j.jobs_results || []).map(r => ({
  cargo: r.title, empresa: r.company_name, ubicacion: r.location,
  descripcion: trunc(r.description, 400),
  link: (r.apply_options && r.apply_options[0] && r.apply_options[0].link) || r.share_link || '',
  publicado: (r.detected_extensions && r.detected_extensions.posted_at) || '',
  via: 'Google Jobs (SerpAPI)'
}));

// --- Tavily ---
const tavily = (name) => get(name).flatMap(j => j.results || []).map(r => ({
  titulo: r.title, link: r.url, fuente: r.url ? new URL(r.url).hostname.replace('www.', '') : 'Tavily',
  fecha: r.published_date || '', resumen: trunc(r.content), via: 'Tavily'
}));

// --- JSearch ---
const jsearch = get('JSearch Empleos Senior').flatMap(j => j.data || []).map(r => ({
  cargo: r.job_title, empresa: r.employer_name,
  ubicacion: [r.job_city, r.job_country].filter(Boolean).join(', '),
  descripcion: trunc(r.job_description, 400),
  link: r.job_apply_link || '',
  publicado: r.job_posted_at_datetime_utc || '',
  via: 'JSearch (Google for Jobs)'
}));

// --- Apify (los items del dataset llegan como items separados con campos variables) ---
const apify = get('Apify LinkedIn Jobs').map(r => ({
  cargo: r.title || r.jobTitle || '', empresa: r.companyName || r.company || '',
  ubicacion: r.location || '',
  descripcion: trunc(r.description || r.descriptionText || '', 400),
  link: r.jobUrl || r.link || r.url || '',
  publicado: r.postedTime || r.publishedAt || '',
  via: 'LinkedIn Jobs (Apify)'
})).filter(x => x.cargo && x.link);

const datos = {
  noticias_chile: limpiar([...serpNews('SerpAPI Noticias Chile'), ...tavily('Tavily Noticias Chile')]).slice(0, 20),
  noticias_internacionales: limpiar([...serpNews('SerpAPI Noticias Internacionales'), ...tavily('Tavily Noticias Internacionales')]).slice(0, 20),
  movimientos_ejecutivos: limpiar([...serpNews('SerpAPI Movimientos Prensa'), ...serpOrganic('SerpAPI Movimientos LinkedIn'), ...tavily('Tavily Movimientos Ejecutivos')]).slice(0, 20),
  empleos: [...serpJobs, ...jsearch, ...apify].slice(0, 30)
};

const conteo = Object.fromEntries(Object.entries(datos).map(([k, v]) => [k, v.length]));
return [{ json: { ...fechas, datos, conteo } }];
